I dig into this problem and get some more info. When pybind11 tries to translate the exception, the exception_ptr is already released but it is not set to `NULL`, and then the crash comes.
Related code:
```cpp
// include\pybind11\pybind11.h:L676
            auto last_exception = std::current_exception(); // here it gets an invalid pointer
            auto &registered_exception_translators = get_internals().registered_exception_translators;
            for (auto& translator : registered_exception_translators) {
                try {
                    translator(last_exception); 
                } catch (...) {
                    last_exception = std::current_exception();
                    continue;
                }
// L1699
    register_exception_translator([](std::exception_ptr p) {
        if (!p) return; // NOT NULL here but an invalid value
        try {
            std::rethrow_exception(p); // crash here because it tries to rethrown an invalid exception_ptr
        } catch (const CppException &e) {
            detail::get_exception_object<CppException>()(e.what());
        }
    });
```

